import redis
from typing import Dict, Any

class RedisCache:
    def __init__(self):
        self.redis_nodes = {
            "node1": {"host": "redis-node-1", "port": 6379},
            "node2": {"host": "redis-node-2", "port": 6380},
            "node3": {"host": "redis-node-3", "port": 6381}
        }
        self.redis_client = None

    def connect_to_redis(self):
        try:
            self.redis_client = redis.Redis(
                host=self.redis_nodes["node1"]["host"],
                port=self.redis_nodes["node1"]["port"]
            )
            print("Connected to Redis")
        except Exception as e:
            print(f"Error connecting to Redis: {str(e)}")

    def store_session_token(self, user_id: str, session_token: str):
        ttl = 60 * 30  # TTL in seconds
        self.redis_client.setex(user_id, ttl, session_token)

    def store_api_key(self, api_key_name: str, api_key_value: str):
        ttl = 60 * 60 * 24 * 7  # TTL in weeks
        self.redis_client.setex(api_key_name, ttl, api_key_value)

    def get_session_token(self, user_id: str) -> str:
        return self.redis_client.get(user_id).decode('utf-8')

    def get_api_key(self, api_key_name: str) -> str:
        return self.redis_client.get(api_key_name).decode('utf-8')


redis_cache = RedisCache()
redis_cache.connect_to_redis()

